def run(cmd):
    print("+", " ".join(map(str, cmd)), flush=True)
    subprocess.run(cmd, check=True)

def probe(path):
    raw = subprocess.check_output([
        "ffprobe","-v","error","-show_entries",
        "format=duration,bit_rate,size",
        "-show_entries","stream=sample_rate,channels",
        "-of","json",str(path)
    ], text=True)
    return json.loads(raw)

def chunks(text, max_chars=2500):
    paras = [p.strip() for p in text.split("\n\n") if p.strip()]
    out, cur = [], ""
    for p in paras:
        if len(cur) + len(p) + 2 <= max_chars:
            cur = (cur + "\n\n" + p).strip()
        else:
            if cur:
                out.append(cur)
            if len(p) <= max_chars:
                cur = p
            else:
                sentences = re.split(r'(?<=[.!?])\s+', p)
                cur = ""
                for s in sentences:
                    if len(cur) + len(s) + 1 <= max_chars:
                        cur = (cur + " " + s).strip()
                    else:
                        if cur:
                            out.append(cur)
                        cur = s
    if cur:
        out.append(cur)
    return out

async def synthesize_chunk(text, voice, target):
    for attempt in range(1,4):
        try:
            comm = edge_tts.Communicate(text=text, voice=voice, rate="-12%")
            await comm.save(str(target))
            if target.exists() and target.stat().st_size > 1000:
                return
        except Exception as exc:
            print(f"tentativa {attempt} falhou: {exc}", file=sys.stderr)
            if attempt == 3:
                raise
            await asyncio.sleep(3 * attempt)

async def build(item):
    num = item["num"]
    title = item["title"]
    voice = item["voice"]
    text = item["text"]
    safe_voice = voice.replace("pt-BR-","").replace("Neural","").upper()
    stem = f"CHATGPT_GPT56_CRIMINOLOGIA_P2_AUDIO_{num:02d}_{title}_{safe_voice}_{VERSION}_{DATE}"
    raw_dir = PARTS / f"{num:02d}"
    raw_dir.mkdir(exist_ok=True)
    part_files = []
    for idx, block in enumerate(chunks(text), 1):
        part = raw_dir / f"part_{idx:03d}.mp3"
        await synthesize_chunk(block, voice, part)
        part_files.append(part)

    concat_file = raw_dir / "concat.txt"
    concat_file.write_text("\n".join(f"file '{p.resolve()}'" for p in part_files), encoding="utf-8")
    joined = raw_dir / "joined.mp3"
    run(["ffmpeg","-y","-f","concat","-safe","0","-i",str(concat_file),"-c","copy",str(joined)])
    info = probe(joined)
    duration = float(info["format"]["duration"])
    out_file = OUT / f"{stem}.mp3"
    fade_out_start = max(duration - 0.6, 0)
    af = f"loudnorm=I=-20:TP=-1.5:LRA=11,afade=t=in:st=0:d=0.4,afade=t=out:st={fade_out_start}:d=0.6"
    run(["ffmpeg","-y","-i",str(joined),"-af",af,"-ac","1","-ar","44100","-b:a","128k",str(out_file)])
    final = probe(out_file)
    return {
        "numero": num,
        "assunto": title,
        "voz": voice,
        "arquivo": out_file.name,
        "palavras": len(text.split()),
        "duracao_segundos": round(float(final["format"]["duration"]),3),
        "bit_rate": final["format"].get("bit_rate",""),
        "tamanho_bytes": final["format"].get("size",""),
        "sample_rate": final["streams"][0].get("sample_rate",""),
        "canais": final["streams"][0].get("channels",""),
    }

async def main():
    preflight_dir = BASE / "preflight"
    preflight_dir.mkdir(exist_ok=True)
    for voice in ["pt-BR-AntonioNeural","pt-BR-FranciscaNeural","pt-BR-ThalitaNeural"]:
        test = preflight_dir / f"{voice}.mp3"
        await synthesize_chunk("Teste PAFE de voz neural em português do Brasil.", voice, test)
        probe(test)

    rows = []
    for item in ITEMS:
        print(f"Gerando {item['num']:02d} - {item['title']}", flush=True)
        rows.append(await build(item))

    total = sum(r["duracao_segundos"] for r in rows)
    if total < 3600:
        raise SystemExit(f"Falha bloqueante: duração total {total/60:.2f} min abaixo de 60 min")

    manifest = OUT / f"CHATGPT_GPT56_CRIMINOLOGIA_P2_MANIFESTO_20_AUDIOS_{VERSION}_{DATE}.csv"
    with manifest.open("w", newline="", encoding="utf-8") as f:
        w = csv.DictWriter(f, fieldnames=list(rows[0].keys()))
        w.writeheader()
        w.writerows(rows)
        w.writerow({"numero":"TOTAL","duracao_segundos":round(total,3)})

    summary = OUT / f"CHATGPT_GPT56_CRIMINOLOGIA_P2_RESUMO_VALIDACAO_{VERSION}_{DATE}.txt"
    lines = [
        f"Arquivos MP3: {len(rows)}",
        f"Duração total: {total/60:.2f} minutos",
        "Motor: edge-tts",
        "Vozes: AntonioNeural, FranciscaNeural, ThalitaNeural",
        "Rate: -12%",
        "Normalização: -20 LUFS, TP -1.5 dBTP, LRA 11",
        "",
    ]
    for r in rows:
        lines.append(f"{r['numero']:02d} | {r['assunto']} | {r['voz']} | {r['duracao_segundos']/60:.2f} min | {r['arquivo']}")
    summary.write_text("\n".join(lines), encoding="utf-8")

    run(["bash","-lc",f"cd '{OUT}' && sha256sum *.mp3 > SHA256SUMS.txt"])
    print(summary.read_text(encoding="utf-8"))

if __name__ == "__main__":
    asyncio.run(main())
